  ('generalpolice-94737317-moex-00024', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '吹風機使用高功率電阻器來發熱，當電流流經電阻器後會消耗電能轉變為熱能。一般吹風機都會標 示額定電壓，若外加電壓大於此值，吹風機容易因電流超載而燒毀。下列敘述何者正確？', '["若吹風機的熱阻絲在固定電阻時，則電阻器消耗的電功率與流經的電流成正比", "若吹風機的熱阻絲在固定電阻時，則電阻器消耗的電功率與流經的電流平方成正比", "在美髮店同時使用三臺吹風機的總電流與使用一臺吹風機的電流一樣大", "在美髮店同時使用三臺吹風機，消耗的電功率總和會比僅使用一臺吹風機來得小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00025', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '如圖的線路中，從a點與b點分別拉出導線，其等效電阻為R ；從b點與c點分別拉出導線，其等 ab 效電阻為R 。R 與R 之比為下列何者？ bc ab bc', '["3/2", "1", "3/4", "1/2"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00026', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '四個電容值均為250μF的電容器A、B、C、D組成的電路如圖所示，當伏特計顯示讀數為1000V， 此時電容器B的正電極板上電荷量為多少庫倫？', '["0.125", "0.250", "0.375", "0.625"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00027', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一磁訊號檢測線圈，其截面積為5×10–2m2、匝數為1000圈，線圈中通過4×10–5T的均勻磁場。若 磁場在0.1s內降至零，則線圈的感應電動勢為何？', '["0.01V", "0.02V", "0.03V", "0.04V"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00028', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '取一條長電線纏繞在一個圓柱上，將一半長度的電線以順時鐘方向緊密纏繞直到圓柱底，另一半長 度的電線以逆時鐘方向繞回原處，製作成線圈甲。另取同長的電線，以順時鐘緊密纏繞直到圓柱底， 再以順時鐘繞回原處製作成線圈乙。若兩線圈通以相同的直流電，下列敘述何者正確？', '["線圈甲的電感值比線圈乙的電感值大", "線圈甲內部的磁場比線圈乙內部的磁場大", "線圈甲內部的磁場方向與線圈乙內部的磁場方向相反", "線圈甲內部的總磁通量接近零"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00029', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '如圖所示為一個RC電路，其中S為切換開關。將開關切到1停留足夠時間，將電容器充飽。然後切 到2，則切到2之後，電容器兩端所儲存的電量變化為何？', '[")C μ (量 電 時間(ms)", ")C μ (量 電 時間(ms)", ")C m (量 電 時間(ms)", ")C m (量 電 時間(ms)"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:45+00:00", "source_pdf_sha1": "2577e653b3d9", "answer_pdf_sha1": "033ac2f41eb6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1510", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
